    vector<long long> sorted_block = block;
    sort(sorted_block.begin(), sorted_block.end());
    vector<long long> sorted_target = target_block;
    sort(sorted_target.begin(), sorted_target.end());
    if (sorted_block != sorted_target) {
        return false;
    }

    // Check for cyclic shift property
    // Concatenate target_block with itself: T_target = T_i + T_i
    vector<long long> doubled_target = target_block;
    doubled_target.insert(doubled_target.end(), target_block.begin(), target_block.end());

